def gen(rng, size):
    n = max(1, size)
    alpha = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
    noise = ' .,:;!?'
    half = [rng.choice(alpha) for _ in range(n // 2)]
    if rng.random() < 0.5:
        core = half + ([rng.choice(alpha)] if n % 2 else []) + [c.swapcase() if c.isalpha() else c for c in reversed(half)]
    else:
        core = [rng.choice(alpha) for _ in range(n)]
    out = []
    for c in core:
        out.append(c)
        if rng.random() < 0.3:
            out.append(rng.choice(noise))
    return [''.join(out)]

