var isPalindrome = function(s) {
    const isAlnum = c => /[a-z0-9]/i.test(c);
    let i = 0, j = s.length - 1;
    while (i < j) {
        if (!isAlnum(s[i])) { i++; continue; }
        if (!isAlnum(s[j])) { j--; continue; }
        if (s[i].toLowerCase() !== s[j].toLowerCase()) return false;
        i++; j--;
    }
    return true;
};
